contract PythStructs {
    // A price with a degree of uncertainty, represented as a price +- a confidence interval.
    //
    // The confidence interval roughly corresponds to the standard error of a normal distribution.
    // Both the price and confidence are stored in a fixed-point numeric representation,
    // `x * (10^expo)`, where `expo` is the exponent.
    //
    // Please refer to the documentation at https://docs.pyth.network/documentation/pythnet-price-feeds/best-practices for how
    // to how this price safely.
    struct Price {
        // Price
        int64 price;
        // Confidence interval around the price
        uint64 conf;
        // Price exponent
        int32 expo;
        // Unix timestamp describing when the price was published
        uint publishTime;
    }

    // PriceFeed represents a current aggregate price from pyth publisher feeds.
    struct PriceFeed {
        // The price ID.
        bytes32 id;
        // Latest available price
        Price price;
        // Latest available exponentially-weighted moving average price
        Price emaPrice;
    }

    struct TwapPriceFeed {
        // The price ID.
        bytes32 id;
        // Start time of the TWAP
        uint64 startTime;
        // End time of the TWAP
        uint64 endTime;
        // TWAP price
        Price twap;
        // Down slot ratio represents the ratio of price feed updates that were missed or unavailable
        // during the TWAP period, expressed as a fixed-point number between 0 and 1e6 (100%).
        // For example:
        //   - 0 means all price updates were available
        //   - 500_000 means 50% of updates were missed
        //   - 1_000_000 means all updates were missed
        // This can be used to assess the quality/reliability of the TWAP calculation.
        // Applications should define a maximum acceptable ratio (e.g. 100000 for 10%)
        // and revert if downSlotsRatio exceeds it.
        uint32 downSlotsRatio;
    }

    // Information used to calculate time-weighted average prices (TWAP)
    struct TwapPriceInfo {
        // slot 1
        int128 cumulativePrice;
        uint128 cumulativeConf;
        // slot 2
        uint64 numDownSlots;
        uint64 publishSlot;
        uint64 publishTime;
        uint64 prevPublishTime;
        // slot 3
        int32 expo;
    }
}

contracts/RoundMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@pythnetwork/pyth-sdk-solidity/IPyth.sol";
import "@pythnetwork/pyth-sdk-solidity/PythStructs.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title RoundMarket
 * @author dotMarket
 * @notice A decentralized, high-frequency pari-mutuel prediction market.
 *         Users bet UP or DOWN on a crypto pair's price movement within
 *         fixed-duration rounds. The winning side splits the total pool
 *         minus a configurable protocol fee.
 * @dev Uses Pyth Network pull-oracle for low-latency price feeds.
 *      Designed for deployment on ARC (EVM-compatible, USDC native gas).
 */
contract RoundMarket is ReentrancyGuard, Ownable {

    // ─── Enums ────────────────────────────────────────────────────────
    enum Position { Up, Down }

    // ─── Structs ──────────────────────────────────────────────────────
    struct Round {
        uint256 roundId;
        int64   startPrice;           // Pyth price at round open
        int64   closePrice;           // Pyth price at round resolve
        uint256 totalUpAmount;        // Total native value bet on UP
        uint256 totalDownAmount;      // Total native value bet on DOWN
        uint256 startTimestamp;       // Block timestamp when opened
        uint256 lockTimestamp;        // Bets rejected after this
        uint256 endTimestamp;         // Round eligible for resolution
        uint256 rewardBaseCalAmount;  // Winning-side total (denominator)
        uint256 rewardAmount;         // Pool minus protocol fee
        bool    resolved;
        bool    canceled;             // Refund mode (tie / one-sided / emergency)
    }

    struct Bet {
        Position position;
        uint256  amount;
        bool     claimed;
    }

    // ─── Immutables ───────────────────────────────────────────────────
    IPyth   public immutable pyth;
    bytes32 public immutable priceFeedId;

    // ─── State ────────────────────────────────────────────────────────
    uint256 public currentRoundId;
    uint256 public roundDuration;     // seconds (120, 180, 300, 600)
    uint256 public lockBuffer;        // seconds before end to stop bets (10)
    uint256 public minBetAmount;      // 0.1 USDC in wei
    uint256 public protocolFeeBps;    // 300 = 3 %
    uint256 public treasuryAmount;    // Accumulated fees claimable by owner
    address public keeperAddress;     // Authorized round operator
    bool    public paused;            // Emergency pause

    mapping(uint256 => Round)                      public rounds;
    mapping(uint256 => mapping(address => Bet))     public bets;
    mapping(address => uint256[])                   public userRounds;

    // ─── Events ───────────────────────────────────────────────────────
    event RoundOpened(
        uint256 indexed roundId,
        uint256 startTimestamp,
        uint256 lockTimestamp,
        uint256 endTimestamp,
        int64   startPrice
    );
    event BetPlaced(
        uint256 indexed roundId,
        address indexed user,
        Position position,
        uint256 amount
    );
    event RoundResolved(
        uint256 indexed roundId,
        int64   closePrice,
        bool    upWins
    );
    event Claimed(
        uint256 indexed roundId,
        address indexed user,
        uint256 amount
    );
    event RoundCanceled(uint256 indexed roundId);
    event KeeperUpdated(address indexed oldKeeper, address indexed newKeeper);
    event Paused(bool isPaused);

    // ─── Modifiers ────────────────────────────────────────────────────
    modifier onlyKeeper() {
        require(msg.sender == keeperAddress, "RM: caller is not the keeper");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "RM: contract is paused");
        _;
    }

    // ─── Constructor ──────────────────────────────────────────────────
    /**
     * @param _pyth           Address of the Pyth contract on ARC
     * @param _priceFeedId    Pyth price feed ID (e.g. BTC/USD)
     * @param _roundDuration  Round length in seconds
     * @param _lockBuffer     Seconds before end when bets lock
     * @param _minBetAmount   Minimum bet in native wei
     * @param _protocolFeeBps Fee in basis points (300 = 3 %)
     * @param _keeper         Initial keeper bot address
     */
    constructor(
        address _pyth,
        bytes32 _priceFeedId,
        uint256 _roundDuration,
        uint256 _lockBuffer,
        uint256 _minBetAmount,
        uint256 _protocolFeeBps,
        address _keeper
    ) Ownable(msg.sender) {
        require(_pyth != address(0), "RM: zero pyth address");
        require(_keeper != address(0), "RM: zero keeper address");
        require(_roundDuration > _lockBuffer, "RM: duration <= buffer");
        require(_protocolFeeBps <= 1000, "RM: fee exceeds 10 %");

        pyth            = IPyth(_pyth);
        priceFeedId     = _priceFeedId;
        roundDuration   = _roundDuration;
        lockBuffer      = _lockBuffer;
        minBetAmount    = _minBetAmount;
        protocolFeeBps  = _protocolFeeBps;
        keeperAddress   = _keeper;
    }

    // ═══════════════════════════════════════════════════════════════════
    //                        KEEPER FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════

    /**
     * @notice Opens a new round, recording the start price from Pyth.
     * @dev    The keeper must pass fresh `priceUpdateData` and enough
     *         msg.value to cover the Pyth update fee. Excess is refunded.
     */
    function openRound(
        bytes[] calldata priceUpdateData
    ) external payable onlyKeeper whenNotPaused {
        // Ensure previous round is settled
        if (currentRoundId > 0) {
            Round storage prev = rounds[currentRoundId];
            require(
                prev.resolved || prev.canceled,
                "RM: previous round still active"
            );
        }

        // ── Pay Pyth & update price feed ──
        uint256 pythFee = pyth.getUpdateFee(priceUpdateData);
        require(msg.value >= pythFee, "RM: insufficient pyth fee");
        pyth.updatePriceFeeds{value: pythFee}(priceUpdateData);

        // ── Read start price ──
        PythStructs.Price memory price = pyth.getPriceNoOlderThan(
            priceFeedId,
            60 // max staleness 60 s
        );

        // ── Create round ──
        currentRoundId++;
        uint256 startTs = block.timestamp;
        uint256 lockTs  = startTs + roundDuration - lockBuffer;
        uint256 endTs   = startTs + roundDuration;

        rounds[currentRoundId] = Round({
            roundId:            currentRoundId,
            startPrice:         price.price,
            closePrice:         0,
            totalUpAmount:      0,
            totalDownAmount:    0,
            startTimestamp:     startTs,
            lockTimestamp:      lockTs,
            endTimestamp:       endTs,
            rewardBaseCalAmount: 0,
            rewardAmount:       0,
            resolved:           false,
            canceled:           false
        });

        // Refund excess value
        _refundExcess(pythFee);

        emit RoundOpened(currentRoundId, startTs, lockTs, endTs, price.price);
    }

    /**
     * @notice Resolves a round by fetching the close price from Pyth
     *         and determining the winning side.
     * @dev    Handles edge cases: no bets, one-sided pool, tie.
     */
    function resolveRound(
        uint256 roundId,
        bytes[] calldata priceUpdateData
    ) external payable onlyKeeper nonReentrant {
        Round storage round = rounds[roundId];

        require(round.startTimestamp != 0, "RM: round does not exist");
        require(block.timestamp >= round.endTimestamp, "RM: round not ended");
        require(!round.resolved && !round.canceled, "RM: already settled");

        // ── Pay Pyth & update price feed ──
        uint256 pythFee = pyth.getUpdateFee(priceUpdateData);
        require(msg.value >= pythFee, "RM: insufficient pyth fee");
        pyth.updatePriceFeeds{value: pythFee}(priceUpdateData);

        // ── Read close price ──
        PythStructs.Price memory price = pyth.getPriceNoOlderThan(
            priceFeedId,
            60
        );

        round.closePrice = price.price;
        round.resolved   = true;

        uint256 totalPool = round.totalUpAmount + round.totalDownAmount;

        // ── No bets at all ──
        if (totalPool == 0) {
            _refundExcess(pythFee);
            emit RoundResolved(roundId, price.price, false);
            return;
        }

        // ── Determine outcome ──
        if (price.price > round.startPrice) {
            // UP wins
            _settleRound(round, round.totalUpAmount, totalPool);
        } else if (price.price < round.startPrice) {
            // DOWN wins
            _settleRound(round, round.totalDownAmount, totalPool);
        } else {
            // TIE — cancel & refund all bettors
            round.canceled    = true;
            round.rewardAmount = totalPool;
        }

        _refundExcess(pythFee);

        emit RoundResolved(
            roundId,
            price.price,
            price.price > round.startPrice
        );
    }

    // ═══════════════════════════════════════════════════════════════════
    //                          USER FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════

    /**
     * @notice Place a bet on the current round.
     * @param roundId  The round to bet on (must be open & unlocked)
     * @param position 0 = Up, 1 = Down
     */
    function placeBet(
        uint256 roundId,
        Position position
    ) external payable nonReentrant whenNotPaused {
        Round storage round = rounds[roundId];

        require(round.startTimestamp != 0, "RM: round does not exist");
        require(block.timestamp >= round.startTimestamp, "RM: not started");
        require(block.timestamp < round.lockTimestamp, "RM: round is locked");
        require(!round.resolved && !round.canceled, "RM: round settled");
        require(msg.value >= minBetAmount, "RM: bet below minimum");
        require(bets[roundId][msg.sender].amount == 0, "RM: already placed bet");

        // Record bet
        bets[roundId][msg.sender] = Bet({
            position: position,
            amount:   msg.value,
            claimed:  false
        });

        if (position == Position.Up) {
            round.totalUpAmount += msg.value;
        } else {
            round.totalDownAmount += msg.value;
        }

        userRounds[msg.sender].push(roundId);

        emit BetPlaced(roundId, msg.sender, position, msg.value);
    }

    /**
     * @notice Claim winnings (or refund if canceled) for a resolved round.
     */
    function claim(uint256 roundId) external nonReentrant {
        Round storage round = rounds[roundId];
        require(round.resolved || round.canceled, "RM: not settled");

        Bet storage bet = bets[roundId][msg.sender];
        require(bet.amount > 0, "RM: no bet found");
        require(!bet.claimed, "RM: already claimed");

        bet.claimed = true;

        uint256 payout = _calculatePayout(round, bet);
        require(payout > 0, "RM: not eligible for payout");

        (bool success, ) = payable(msg.sender).call{value: payout}("");
        require(success, "RM: transfer failed");

        emit Claimed(roundId, msg.sender, payout);
    }

    // ═══════════════════════════════════════════════════════════════════
    //                         VIEW FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════

    /**
     * @notice Returns full round data.
     */
    function getRound(uint256 roundId) external view returns (Round memory) {
        return rounds[roundId];
    }

    /**
     * @notice Returns a user's bet for a given round.
     */
    function getUserBet(
        uint256 roundId,
        address user
    ) external view returns (Bet memory) {
        return bets[roundId][user];
    }

    /**
     * @notice Returns all round IDs a user has participated in.
     */
    function getUserRounds(
        address user
    ) external view returns (uint256[] memory) {
        return userRounds[user];
    }

    /**
     * @notice Checks if a user can claim winnings for a given round.
     */
    function claimable(
        uint256 roundId,
        address user
    ) external view returns (bool) {
        Round memory round = rounds[roundId];
        Bet memory bet = bets[roundId][user];

        if (bet.amount == 0 || bet.claimed) return false;
        if (!round.resolved && !round.canceled) return false;

        return _calculatePayout(round, bet) > 0;
    }

    /**
     * @notice Returns the current payout multiplier for each side.
     * @dev    Multiplier is scaled by 1e4 (10000 = 1.0x). Returns 0 if
     *         no bets exist on that side.
     */
    function getMultipliers(
        uint256 roundId
    ) external view returns (uint256 upMultiplier, uint256 downMultiplier) {
        Round memory round = rounds[roundId];
        uint256 totalPool = round.totalUpAmount + round.totalDownAmount;

        if (totalPool == 0) return (0, 0);

        uint256 rewardPool = totalPool - (totalPool * protocolFeeBps) / 10000;

        if (round.totalUpAmount > 0) {
            upMultiplier = (rewardPool * 10000) / round.totalUpAmount;
        }
        if (round.totalDownAmount > 0) {
            downMultiplier = (rewardPool * 10000) / round.totalDownAmount;
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    //                        ADMIN FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════

    function setKeeper(address _keeper) external onlyOwner {
        require(_keeper != address(0), "RM: zero address");
        emit KeeperUpdated(keeperAddress, _keeper);
        keeperAddress = _keeper;
    }

    function setProtocolFee(uint256 _feeBps) external onlyOwner {
        require(_feeBps <= 1000, "RM: fee exceeds 10 %");
        protocolFeeBps = _feeBps;
    }

    function setMinBetAmount(uint256 _minBet) external onlyOwner {
        minBetAmount = _minBet;
    }

    function setRoundDuration(uint256 _duration) external onlyOwner {
        require(_duration > lockBuffer, "RM: duration <= buffer");
        roundDuration = _duration;
    }

    function setLockBuffer(uint256 _buffer) external onlyOwner {
        require(roundDuration > _buffer, "RM: buffer >= duration");
        lockBuffer = _buffer;
    }

    function setPaused(bool _paused) external onlyOwner {
        paused = _paused;
        emit Paused(_paused);
    }

    /**
     * @notice Withdraw accumulated protocol fees.
     */
    function withdrawTreasury() external onlyOwner {
        uint256 amount = treasuryAmount;
        require(amount > 0, "RM: nothing to withdraw");
        treasuryAmount = 0;

        (bool success, ) = payable(owner()).call{value: amount}("");
        require(success, "RM: transfer failed");
    }

    /**
     * @notice Emergency cancel a stuck round. All bettors can claim refunds.
     */
    function cancelRound(uint256 roundId) external onlyOwner {
        Round storage round = rounds[roundId];
        require(!round.resolved, "RM: already resolved");
        require(!round.canceled, "RM: already canceled");

        round.canceled    = true;
        round.rewardAmount = round.totalUpAmount + round.totalDownAmount;

        emit RoundCanceled(roundId);
    }

    // ═══════════════════════════════════════════════════════════════════
    //                       INTERNAL HELPERS
    // ═══════════════════════════════════════════════════════════════════

    /**
     * @dev Settles a round. If the winning side has no bets, cancel
     *      (refund everyone). Otherwise deduct fee and record reward pool.
     */
    function _settleRound(
        Round storage round,
        uint256 winnerSideAmount,
        uint256 totalPool
    ) internal {
        if (winnerSideAmount == 0) {
            // Nobody bet on the winning side → refund all
            round.canceled     = true;
            round.rewardAmount = totalPool;
            return;
        }

        uint256 fee = (totalPool * protocolFeeBps) / 10000;
        treasuryAmount += fee;

        round.rewardBaseCalAmount = winnerSideAmount;
        round.rewardAmount        = totalPool - fee;
    }

    /**
     * @dev Calculates payout for a bet given the round outcome.
     */
    function _calculatePayout(
        Round memory round,
        Bet memory bet
    ) internal pure returns (uint256) {
        if (round.canceled) {
            // Refund the original bet
            return bet.amount;
        }

        if (round.rewardBaseCalAmount == 0) {
            // Safety: should not happen if contract logic is correct
            return 0;
        }

        bool upWins   = round.closePrice > round.startPrice;
        bool downWins = round.closePrice < round.startPrice;

        bool isWinner = (upWins && bet.position == Position.Up)
                     || (downWins && bet.position == Position.Down);

        if (!isWinner) return 0;

        return (bet.amount * round.rewardAmount) / round.rewardBaseCalAmount;
    }

    /**
     * @dev Refunds any excess native value sent above the Pyth fee.
     */
    function _refundExcess(uint256 pythFee) internal {
        if (msg.value > pythFee) {
            (bool success, ) = payable(msg.sender).call{
                value: msg.value - pythFee
            }("");
            require(success, "RM: refund failed");
        }
    }

    /**
     * @dev Allow the contract to receive native tokens (needed for
     *      keeper refunds and general operation).
     */
    receive() external payable {}
}
